#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-26

set -euo pipefail

# Diff Scanner for /ork:expect
# Usage: bash diff-scan.sh [unstaged|branch|commit]
# Output: JSON with changed files, classified by level

TARGET="${1:-unstaged}"

case "$TARGET" in
  unstaged)
    FILES=$(git diff --name-only 2>/dev/null || true)
    DIFF_CMD="git diff"
    ;;
  branch)
    BASE=$(git merge-base main HEAD 2>/dev/null || echo "HEAD~1")
    FILES=$(git diff "${BASE}...HEAD" --name-only 2>/dev/null || true)
    DIFF_CMD="git diff ${BASE}...HEAD"
    ;;
  commit)
    FILES=$(git diff HEAD~1 --name-only 2>/dev/null || true)
    DIFF_CMD="git diff HEAD~1"
    ;;
  *)
    echo "Unknown target: $TARGET" >&2
    exit 1
    ;;
esac

if [[ -z "$FILES" ]]; then
  echo '{"target":"'"$TARGET"'","files":[],"stats":{"total":0,"added":0,"modified":0,"deleted":0}}'
  exit 0
fi

# Classify files
ADDED=0
MODIFIED=0
DELETED=0
FILE_JSON="["
FIRST=true

while IFS= read -r file; do
  [[ -z "$file" ]] && continue

  # Skip non-source files
  if echo "$file" | grep -qE '\.(lock|log|map)$|node_modules|\.git/'; then
    continue
  fi

  # Determine status
  if ! git show HEAD:"$file" &>/dev/null 2>&1; then
    STATUS="added"
    ADDED=$((ADDED + 1))
  elif ! [[ -f "$file" ]]; then
    STATUS="deleted"
    DELETED=$((DELETED + 1))
  else
    STATUS="modified"
    MODIFIED=$((MODIFIED + 1))
  fi

  # Detect file type
  case "$file" in
    *.tsx|*.jsx) TYPE="component" ;;
    *.ts|*.js)   TYPE="logic" ;;
    *.css|*.scss) TYPE="style" ;;
    *.md|*.mdx)  TYPE="docs" ;;
    *.json|*.yaml|*.yml) TYPE="config" ;;
    *) TYPE="other" ;;
  esac

  if [[ "$FIRST" == "true" ]]; then
    FIRST=false
  else
    FILE_JSON+=","
  fi
  FILE_JSON+='{"path":"'"$file"'","status":"'"$STATUS"'","type":"'"$TYPE"'"}'
done <<< "$FILES"

FILE_JSON+="]"
TOTAL=$((ADDED + MODIFIED + DELETED))

echo '{"target":"'"$TARGET"'","files":'"$FILE_JSON"',"stats":{"total":'"$TOTAL"',"added":'"$ADDED"',"modified":'"$MODIFIED"',"deleted":'"$DELETED"'}}'
